var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"흐이익!?","JPN":"ふええっ！？","ENG":"Eeeek!!","TWN":"嗚嗚嗚！？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"하아…… 하…… 바, 바람 소리였구나. 깜짝이야.","JPN":"はあ……は……か、風の音だったんだね。ビックリした。","ENG":"Phew... I-it was just the wind. *Sigh*","TWN":"呼……呼……原來是風聲，嚇我一跳。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으으, 이럴 줄 알았어. 얌전히 시그마를 따라갈 걸 왜 허세나 부려 가지고…….","JPN":"うう、こうなるとは思ってたんだ。強がってないで、大人しくシグマについていけばよかった……","ENG":"Ngh... I knew this would happen. I should've just followed Sigma. Why did I have to act all tough back there...","TWN":"嗚，早知如此就乖乖跟著西格瑪就好，幹嘛打腫臉充胖子……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기 계셨군요. 헤이븐 님.","JPN":"ここにいたんですね。ヘイブン様。","ENG":"So this is where you’ve been, Mr. Haven.","TWN":"天堂先生，原來您在這。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으아아아아! 요괴 마녀다!!","JPN":"うわああああ！　妖怪魔女だ！！","ENG":"AAAAH!! It's a witch monster!!","TWN":"啊啊啊啊！是老巫婆！！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"누구더러 요괴 마녀라는 거야!?","JPN":"誰が妖怪魔女よ！？","ENG":"Who are you calling a witch monster?!","TWN":"你叫誰老巫婆！？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤, 헤론이야? 네가 여긴 어떻게……?","JPN":"へ、ヘロン？　どうやってここに……？","ENG":"H-Heron? I-is that you? But h-how did you know I...?","TWN":"海…海倫？你怎麼會在這……？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"가면도 없이 용케 돌아다니셨군요. 그러다 공포증이라도 도지면 어쩌시려구요.","JPN":"よくも仮面なしで歩き回れましたね。恐怖症が酷くなったらどうするんです？","ENG":"I'm surprised you’ve been running around like this without your mask. What if your phobia kicks in, hmm?","TWN":"沒戴面具還到處亂跑，萬一恐懼症復發的話怎麼辦？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"손님들에게 헤이븐 님의 볼품없는 꼬락서니를 들켰을까 봐 어찌나 조마조마하던지.","JPN":"お客様にヘイブン様のみっともない姿がバレてないか、どれだけハラハラしたことか。","ENG":"I have been so on edge, wondering what will happen if our guests found out that Haven was a scared little kid.","TWN":"而且我也很擔心，萬一您這副模樣被人看到可就不好啦。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……여긴 왜 왔어.","JPN":"……なんで来たんだよ。","ENG":"...Why are you here?","TWN":"……你來這做什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당연히 헤이븐 님을 모시러 왔죠.","JPN":"もちろんヘイブン様をお迎えに来たんです。","ENG":"To escort you, of course.","TWN":"當然是來帶您回去的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 랜드의 주인이 자리를 오래 비우면 아랫사람들이 불안해하니까요.","JPN":"ヘイブンランドの主が長く留守をしてると、下の者たちが不安に思いますからね。","ENG":"If the owner of Havenland is away for too long, his employees will become anxious.","TWN":"天堂樂園的主人若是離開位置太久，底下的人會不安的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"언제 갈지는……. 내가 정해.","JPN":"いつ帰るかは……僕が決める。","ENG":"I decide... when I go back.","TWN":"什麼時候要回去……由我決定。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"돌아가서 기다리고 있어. 묻고 싶은 얘기가 많으니까.","JPN":"帰って待っててよ。聞きたいことがたくさんあるから。","ENG":"Go back to your office and wait for me there. There are a lot of questions you need to answer.","TWN":"你先回去等著，我有很多事要問你。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아뇨. 오히려 제가 묻고 싶네요.","JPN":"いいえ。むしろ私がお聞きしたいですわ。","ENG":"No. I'm the one with all the questions.","TWN":"不，我才想問您。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저 아이들이 위저드를 무너뜨린 배은망덕한 것들이란 사실을 알고 계셨나요?","JPN":"あの子たちがウィザードをめちゃくちゃにした恩知らずだということをご存じですか？","ENG":"Did you know that those brats are the ones who tore down Wizard?","TWN":"您知道那些人是毀掉巫師的叛徒嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 다른 아이들이 위저드의 도움을 받지 못하게 되었다는 것도?","JPN":"そのせいで他の子たちがウィザードの支援を受けられなくなったということは？","ENG":"And that's why the other children there can't receive any help?","TWN":"您也知道，有許多孩子因此而無法受到巫師的幫助嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"설마 저런 불량한 가출 청소년들이 떠들어대는 말에 귀 기울이신 건 아니죠, 헤이븐 님?","JPN":"まさかあのタチの悪い家出少女たちの話を真に受けたのではないでしょうね、ヘイブン様。","ENG":"Don't tell me you actually believed what those darn kids told you, Mr. Haven.","TWN":"那些離家出走的不良少女說的話，您應該沒放在心上吧，天堂先生？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"헤론…… 아니, 누나!","JPN":"ヘロン……いや、姉さん！","ENG":"Heron... I mean, Sis!","TWN":"海倫……不，姊姊！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"둘만 있을 때는 헤이븐 님이라고 그만 불러!","JPN":"二人だけの時にはヘイブン様って呼ばないでよ！","ENG":"Don't call me \\"Mr. Haven\\" when it's just the two of us!","TWN":"只有我們二個的時候不要叫我天堂先生！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"내가 아무것도 모르는 줄 알아?","JPN":"僕が何も知らないとでも思ってる？","ENG":"Do you really think I'm that clueless?","TWN":"你以為我什麼都不知道嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"언제부턴가 위저드에서 오는 아이들의 분위기가 점점 이상해졌잖아.","JPN":"いつからかウィザードから来る子たちの雰囲気がだんだんおかしくなってきたんだ。","ENG":"I know that the kids from Wizard have been acting weird for some time now.","TWN":"不知道從什麼時候開始，巫師來的孩子變得很不對勁。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"허드슨처럼 신나게 놀 줄도 모르고, 호란처럼 자기가 좋아하는 것도 없어.","JPN":"ハドソンみたいに楽しく遊ぶ方法も知らないし、ホランみたいに自分が好きなこともない。","ENG":"They don't know how to let loose like Hudson, or what they are interested in like Horan!","TWN":"不像哈德森那樣盡情地玩，也不像小蘭那樣知道自己喜歡什麼。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"다들 뭘 하자고 하면 적당히 장단만 맞춰 줄 뿐이라고.","JPN":"みんな何かやろうって言っても適当に合わせてくれるだけなんだ。","ENG":"All they do is halfheartedly follow along with whatever others want to do.","TWN":"他們只會一個口令一個動作。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"일이 바빠서 최근에 대화를 못 나눴더니 별 오해가 다 쌓이네요.","JPN":"最近仕事で忙しくてちゃんと会話をしてなかったせいか、誤解が重なってしまいましたね。","ENG":"It appears that there's been a misunderstanding, since we haven't talked in a while due to the busy schedule.","TWN":"最近事情太多，比較少和您說話，沒想到累積不少誤會呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저 아이들은 알아서 잘 처리할 테니 이 일에는 그만 신경 끄세요.","JPN":"あの子たちは私がちゃんと処理しますから、もうこの件にはお気遣いなく。","ENG":"I'll take care of those kids, so don't press this matter any further.","TWN":"那些人我會自己看著辦，就不勞煩您再費心。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아니. 누나가 빠져. 저 아이들은 내 이름을 걸고 무사히 돌려보낼 거야.","JPN":"いや。姉さんは下がってて。あの子たちは僕の名にかけて無事に帰すから。","ENG":"No. You step away. I swear on my name that I'll make sure to send those kids home without a scratch on them.","TWN":"不，姊姊你別插手，我用我的名義保證，我一定會送她們安全離開。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아…… 헤이븐 님.","JPN":"はあ……ヘイブン様。","ENG":"*Sigh...* Mr. Haven.","TWN":"哀……天堂先生。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"집 없이 거리를 싸돌아다니는 아이들이란 교활하기 이를 데 없답니다.","JPN":"家もなく街を彷徨う子どもたちなんて、とてもずる賢いんですよ。","ENG":"These orphans are as sly and cunning as they come.","TWN":"您不知道那些在街頭流浪的孩子有多狡猾。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"앞에선 불쌍한 척, 세상에서 자기가 가장 불행한 척 하지만 뒤에서는 어른을 이용하고 등쳐 먹을 생각뿐이에요.","JPN":"表向きは不憫で世界一不幸であるかのように振る舞っても、裏では大人を利用してだまし取る気満々なのです。","ENG":"They pretend to be poor and miserable in front of us, but all they ever think about is how to rob us blind.","TWN":"在人前裝作一副可憐樣，好像他是全世界最不幸的人，但背後只是想利用大人敲詐一番而已。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그만 좀 해!","JPN":"やめてくれ！","ENG":"Enough!","TWN":"別再說了！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"우리도 그랬어! 우리도 아빠에게 맞다가 죽을까 봐 집을 나온 거였잖아!","JPN":"僕達だって同じだ！　父さんに殴られて死ぬと思ったから家を出たんじゃないか！","ENG":"We were like them too! We ran away from home because we were afraid that Dad would beat us to death!","TWN":"我們也一樣！我們也是怕被爸爸打死才離家出走的！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"지금이라도 늦지 않았어, 누나.","JPN":"今からでも遅くないよ、姉さん。","ENG":"It’s not too late, Sis.","TWN":"姊姊，現在還來得及。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"무슨 짓을 저질렀는지 모르겠지만, 아직 바로잡을 기회가…….","JPN":"何をしたのかはわからないけど、まだ正すチャンスが……","ENG":"I don't know what you did, but there's still time to m–","TWN":"雖然我不清楚你做了什麼，但還有機會可以挽回……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"맞아. 헤이븐. 우리도 그것들과 같은 신세였지.","JPN":"そうね。ヘイブン。私たちも同じ運命だった。","ENG":"You're right, Haven. We were like them.","TWN":"你說的沒錯，天堂。我們和他們的處境一樣。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"카운터로 각성했으면서 그 주정뱅이 놈에게 반항 한 번 안 한 너 때문에.","JPN":"カウンターとして覚醒したくせに、あの酔っ払いに一度も抵抗しなかったあなたのせいで。","ENG":"Because you, who got awakened as a Counter, couldn’t give that drunkard a shot of his own medicine.","TWN":"因為你覺醒成制裁者後，卻一次也沒有反抗過那個酒鬼。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그건… 아빠도 엄마가 돌아가신 것 때문이었어.","JPN":"それは……父さんも、母さんが亡くなったのが原因だったから。","ENG":"That's because... Dad only lashed out because of Mom's death.","TWN":"那是因為…爸爸也是因為媽媽過世才會那樣。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래? 그 쓰레기가 가여워서 샌드백으로 살기로 결심했다고?","JPN":"ふうん？　あの人間のクズを憐れんで、サンドバッグとして生きようと決めたってわけ？","ENG":"Oh yeah? You felt sorry for that piece of trash, so you decided to spend your life as his punching bag?","TWN":"是嗎？你是因為那個垃圾很可憐，才下定決心要當他的出氣包嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼 그냥 살던 대로 살지 왜 날 따라나왔어. 뒤치다꺼리 해 줄 사람이 없어질까 봐 아쉬웠니?","JPN":"じゃあそのまま暮らせばいいのになんで私について出てきたのよ。面倒を見てくれる人がいなくなるのが心配だったから？","ENG":"Then why did you run away with me instead of staying there? Were you sad that you would have to do all the chores by yourself?","TWN":"那你繼續過那種生活就好啦，為何要跟著我離開家？是怕沒人替你擦屁股嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"누나! 나는 누나라도……!","JPN":"姉さん！　僕は姉さんだけでも……！","ENG":"Sis! All I wanted was–!","TWN":"姊姊！我也很想……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"난 네가 원하는 건 전부 해 줬잖아!","JPN":"私はあなたのやりたいこと全部やらせてあげたじゃない！","ENG":"I gave you everything you ever wanted!","TWN":"你想要的我全都有替你做到不是嗎！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"놀이동산? 카드 게임? 거지 같은 애새끼들 돌봐 주는 거?","JPN":"遊園地？　カードゲーム？　クソガキの面倒？","ENG":"An amusement park! Card games! Even looking after those rancid kids!","TWN":"遊樂園？桌遊？照顧那些像乞丐的小鬼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐! 또 뭐가 필요한데! 어!?","JPN":"何よ！　まだ何が必要なわけ？　ねえ！？","ENG":"What else?! What else do you want from me?! Huh?!","TWN":"你現在又想要什麼！嗯！？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……지켜 주고 싶었던 건데.","JPN":"……守ってあげたかっただけなんだ。","ENG":"...to protect you.","TWN":"……保護姊姊。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하. 넌 매번 그렇게 어디서 주워 들은 말을 나불거릴 줄만 알지.","JPN":"は。あなたはいつもどこかで聞いた言葉を喋ってるだけだわ。","ENG":"*Sigh* You only know how to babble around words you picked up somewhere.","TWN":"哈，你每次都只會說這些不知道從哪學來的好聽話。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 뭘 해 주면 이건 안 되네, 저건 범죄네 투정만 부렸던 주제에.","JPN":"私が何かをやってあげると、これはダメとかあれは犯罪だとか愚痴だけ言ってたくせに。","ENG":"All you do is whine about how everything I try to do for you is illegal.","TWN":"我做什麼都不行，說什麼那是犯法的，嫌東嫌西的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래. 길거리나 전전하던 우리가 이렇게 성장한 게 이것 때문인 건 사실이야.","JPN":"そう。街を転々としていた私たちがここまで成長したのはこれのおかげだってことは事実よ。","ENG":"And yes. It's true that we were able to become what we are today because of this.","TWN":"沒錯，在街頭流浪的我們之所以能長大，就是因為這個。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그건…… 내 가면…….","JPN":"それは……僕の仮面……","ENG":"That's... My mask...","TWN":"那是……我的面具……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그리고 이걸 누가 줬더라?","JPN":"これをあげたのは誰だったかしらね。","ENG":"Do you remember who gave this to you?","TWN":"這是誰給你的？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"나야. 겁쟁이였던 너에게 숨을 곳을 마련해 준 것도 나였어.","JPN":"私よ。臆病者だったあなたに、隠れるところを作ってあげたのも私だった。","ENG":"I did. I was the one who gave poor little Haven a place to hide.","TWN":"是我！是誰替你這個膽小鬼預備可以躲藏的地方的？也是我！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"애들이랑 놀고 싶었잖아? 응? 그래서 그럴 수 있게 해 줬잖아?","JPN":"子どもたちと遊びたかったんでしょう？　ね？　それで遊べるようにしてあげたじゃない。","ENG":"You said you wanted to play with other kids. So I made that happen, didn't I?","TWN":"你想和孩子們一起玩？是吧？那我就讓你和孩子們一起玩不是嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그런데 넌 누날 위해서 남들 겁 주는 것 하나 제대로 못 해 주지.","JPN":"なのにあなたは姉さんのために人を脅かすこともまともにできないなんてね。","ENG":"But you can't even do the one thing I asked you to do for me.","TWN":"但你連為我去威嚇別人這點小事都做不到。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 없어지고 나면 누가 널 신경 써 줄까? 가면 뒤에 숨은 너만 아는 그 멍청이들?","JPN":"私がいなくなったら誰があなたのことを考えてくれると思う？　仮面の裏に隠されたあなたを知ってる、あのバカたち？","ENG":"Who do you think will take care of you when I'm gone, hmm? Those morons who only know the masked version of you?","TWN":"要是沒有我，還有誰會在乎你？那些認識躲在面具背後的你的傻瓜嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"후우……. 골치야.","JPN":"ふぅ……頭痛いわね。","ENG":"*Sigh* What a pain...","TWN":"呼……頭好疼。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님, 제발 부탁이니까 해 달라는 것만 제대로 해 주세요. 네?","JPN":"ヘイブン様、お願いですから指示したことだけをちゃんとやってください。ね？","ENG":"So please, Mr. Haven. Just do what I tell you to do, okay?","TWN":"天堂先生，拜託您，請做好我麻煩您的事吧，好嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……아이들에게 해만 끼치지 않겠다고 약속해.","JPN":"……子どもたちには怪我させないって約束しろ。","ENG":"...Promise me that you won't hurt the children.","TWN":"……答應我，你不會傷害那些孩子。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼요. 물론 그래야죠.","JPN":"わかりました。もちろんですとも。","ENG":"Yes, of course.","TWN":"當然，當然不會。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그러니 제가 혼쭐을 내지 않아도 되게, 그 멍청한 아이들에게 가르쳐 주세요.","JPN":"だから私がこらしめなくても済むように、あのバカな子たちに教えてあげてください。","ENG":"I won't have to scold them as long as you teach those foolish kids...","TWN":"所以在我出手教訓她們之前，請您先教教她們吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이 곳의 주인이 누군지 말이야.","JPN":"ここの主が誰なのかをね。","ENG":"Who the real owner of this place is.","TWN":"誰才是這裡的主人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};